<template>
  <view class="container">
    <!-- 顶部标题栏 -->
    <view class="header">
      <u-icon name="arrow-left" size="24" @click="goBack"></u-icon>
      <text class="title">用药管理工具</text>
      <view class="placeholder"></view>
    </view>

    <!-- 加载状态 -->
    <view v-if="loading" class="loading-state">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="loading-text">加载中...</text>
    </view>

    <!-- 空状态 -->
    <view v-else-if="tools.length === 0" class="empty-state">
      <u-empty mode="data" text="暂无可用工具"></u-empty>
    </view>

    <!-- 工具列表 -->
    <view v-else class="list-content">
      <u-cell-group>
        <u-cell
          v-for="tool in tools"
          :key="tool.id"
          :title="tool.title"
          :label="tool.description"
          is-link
          @click="downloadFile(tool)"
        >
          <template #value>
            <view class="cell-value">
              <text class="file-size">{{ tool.fileSize }}</text>
              <u-icon name="download" size="18" color="#1989fa"></u-icon>
            </view>
          </template>
        </u-cell>
      </u-cell-group>
    </view>
  </view>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue'
import request from '@/utils/request'

// 类型定义
interface Tool {
  id: number
  title: string
  description: string
  fileType: 'excel' | 'word' | 'pdf'
  fileSize: string
  downloadUrl: string
  updatedAt: string
}

// 响应式数据
const tools = ref<Tool[]>([])
const loading = ref(false)

// 获取工具列表
const fetchTools = async () => {
  loading.value = true
  try {
    const res = await request.get('/api/resource/drug/tools')
    // 兼容不同的返回结构
    tools.value = res.data?.list || res.data || res.data || []
  } catch (error) {
    uni.__f__('error','at pages/resource/drug/MedicationTool.vue:71','获取工具列表失败:', error)
    tools.value = []
    uni.showToast({ title: '加载工具列表失败，请稍后再试', icon: 'none' })
  } finally {
    loading.value = false
  }
}

// 下载文件
const downloadFile = async (tool: Tool) => {
  uni.showLoading({ title: '下载中...' })
  try {
    // 使用 uni.downloadFile 进行跨端下载
    const downloadRes = await new Promise<UniApp.DownloadFileSuccessCallbackResult>((resolve, reject) => {
      uni.downloadFile({
        url: tool.downloadUrl,
        success: (res) => {
          if (res.statusCode === 200) {
            resolve(res)
          } else {
            reject(new Error(`下载失败: ${res.statusCode}`))
          }
        },
        fail: reject
      })
    })

    // 打开文档
    uni.openDocument({
      filePath: downloadRes.tempFilePath,
      showMenu: true, // 显示右上角菜单
      success: () => {
        uni.hideLoading()
        uni.showToast({ title: '打开成功', icon: 'success' })
      },
      fail: (err) => {
        uni.__f__('error','at pages/resource/drug/MedicationTool.vue:107','打开文档失败:', err)
        uni.hideLoading()
        uni.showToast({ title: '无法打开该文件类型', icon: 'none' })
      }
    })
  } catch (error) {
    uni.__f__('error','at pages/resource/drug/MedicationTool.vue:113','下载文件失败:', error)
    uni.hideLoading()
    uni.showToast({ title: '下载失败，请检查网络', icon: 'none' })
  }
}

// 返回上一页
const goBack = () => {
  uni.navigateBack({
    delta: 1
  })
}

// 生命周期
onMounted(() => {
  fetchTools()
})
</script>

